// Arbeitnow: paginate up to 10 pages, relaxed client-side filters
const config = JSON.parse(require('fs').readFileSync(
  ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/config.json', 'utf-8'
));
const MAX_PAGES = config.an_max_pages || 10;
const DELAY_MS = config.an_delay_ms || 5000;
const cutoff = Date.now() - (config.an_days_back || 30) * 24 * 60 * 60 * 1000;

const titleKw = ['python','backend','back-end','back end','data engineer','data engineering','software engineer','software developer','platform engineer','api developer','developer python','entwickler','softwareentwickler','devops','site reliability','sre','etl','junior developer','junior engineer','flask','django','fastapi','developer','engineer','cloud','infrastructure','programmierer','informatiker','application engineer','system engineer','web developer','webentwickler','it engineer','automation','machine learning','ml engineer','data scientist','data analyst','full stack','fullstack'];
const tagKw = ['python','backend','data','engineering','devops','api','flask','django','fastapi','docker','aws','postgresql','kubernetes','linux','sql','java','node','typescript','go','rust','cloud','azure','gcp','terraform','ci/cd','microservices'];
const locKw = ['hamburg','berlin','germany','remote','deutschland','münchen','munich','frankfurt','köln','cologne','deutsch','düsseldorf','hannover','stuttgart','bremen','nürnberg','nuremberg','leipzig','dresden','essen','dortmund','bonn','karlsruhe','mannheim','freiburg','heidelberg','europe','eu','dach'];
const negKw = ['manager','consultant','designer','marketing','sales','recruiter','sap','sap consultant','abap','salesforce','product owner','scrum master','project manager','buchhalter','accounting','finance','legal','rechtsanwalt','jurist','pflege','nurse','arzt','physician','lehrer','teacher','werkstudent','working student','dual student','intern','praktikant','trainee','senior director','vp ','vice president','head of','chief','principal','staff engineer','lead architect'];
const engWords = ['the','and','you','we','team','experience','requirements','about','our','will','work','join','role','position'];

function isLikelyEnglish(desc) {
  const sample = (desc || '').substring(0, 500).toLowerCase();
  const hits = engWords.filter(w => sample.includes(w)).length;
  return hits >= 3;
}

const allJobs = [];
const seen = new Set();
const errors = [];
var lastPage = 0;

for (let page = 1; page <= MAX_PAGES; page++) {
  if (page > 1) await new Promise(r => setTimeout(r, DELAY_MS));
  lastPage = page;
  let body;
  try {
    body = await this.helpers.httpRequest({ method: 'GET', url: `https://www.arbeitnow.com/api/job-board-api?page=${page}`, json: true });
  } catch (e) { errors.push({ page, error: e.message || String(e) }); break; }
  const data = body.data || [];
  if (data.length === 0) break;

  let allOld = true;
  for (const job of data) {
    const created = new Date(job.created_at * 1000 || job.created_at).getTime();
    if (created > cutoff) allOld = false;

    const t = (job.title || '').toLowerCase();
    const l = (job.location || '').toLowerCase();
    const tags = (job.tags || []).map(t => t.toLowerCase());
    const titleMatch = titleKw.some(k => t.includes(k));
    const tagMatch = tagKw.some(k => tags.includes(k));
    const locMatch = locKw.some(k => l.includes(k)) || job.remote;
    const negMatch = negKw.some(k => t.includes(k));

    if (!negMatch && (titleMatch || tagMatch || locMatch) && created > cutoff) {
      const key = job.slug || job.url || job.title;
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push(job);
      }
    }
  }
  if (allOld) break;
  const maxPage = body.meta?.last_page || MAX_PAGES;
  if (page >= maxPage) break;
}

if (allJobs.length === 0) return [];

function parseSalary(job) {
  let min = job.salary_min || null;
  let max = job.salary_max || null;
  let currency = job.salary_currency || null;
  if (!min && job.salary) {
    const nums = String(job.salary).replace(/[.,]/g, '').match(/\d+/g);
    if (nums && nums.length >= 2) { min = Number(nums[0]); max = Number(nums[1]); }
    else if (nums && nums.length === 1) { min = Number(nums[0]); }
    if (!currency && /eur|€/i.test(job.salary)) currency = 'EUR';
    if (!currency && /usd|\$/i.test(job.salary)) currency = 'USD';
    if (!currency && /chf/i.test(job.salary)) currency = 'CHF';
    if (!currency && /gbp|£/i.test(job.salary)) currency = 'GBP';
  }
  return { salary_min: min, salary_max: max, salary_currency: currency || (min ? 'EUR' : null) };
}

const _crawlMeta = {
  source: 'arbeitnow',
  pages_fetched: lastPage,
  total_results: allJobs.length,
  fetch_errors: errors.length,
  errors: errors.slice(0, 10),
};

const mapped = allJobs.map(j => {
  const desc = (j.description || '').substring(0, config.description_max_chars || 5000);
  const sal = parseSalary(j);
  return { json: {
    source: 'arbeitnow',
    external_id: j.slug || '',
    url: j.url || `https://www.arbeitnow.com/view/${j.slug}`,
    title: j.title || '',
    company: j.company_name || '',
    location: j.location || '',
    description: desc,
    tags: j.tags || [],
    remote: j.remote || false,
    likely_english: isLikelyEnglish(desc),
    salary_min: sal.salary_min,
    salary_max: sal.salary_max,
    salary_currency: sal.salary_currency,
  }};
});
if (mapped.length > 0) mapped[0].json._crawlMeta = _crawlMeta;
return mapped;

// Arbeitsagentur: run multiple server-side filtered searches + fetch full descriptions
const config = JSON.parse(require('fs').readFileSync(
  ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/config.json', 'utf-8'
));
const BASE = 'https://rest.arbeitsagentur.de/jobboerse/jobsuche-service/pc/v4/jobs';
const HEADERS = { 'X-API-Key': 'jobboerse-jobsuche', 'User-Agent': 'Mozilla/5.0', 'Accept': 'application/json' };

const searches = [
  'Python Developer', 'Backend Engineer', 'Data Engineer', 'Software Engineer',
  'Python Entwickler', 'Software Entwickler', 'Backend Entwickler',
  'ETL Developer', 'ETL Entwickler', 'Cloud Engineer',
  'Flask', 'Django', 'FastAPI', 'PHP Symfony', 'DevOps'
];
const commonParams = 'wo=Hamburg&umkreis=200&veroeffentlichtseit=30&pav=false&zeitarbeit=false&size=100';

const seenIds = new Set();
const jobs = [];
const errors = [];
const MAX_PAGES = config.aa_max_pages || 3;

for (let i = 0; i < searches.length; i++) {
  for (let page = 1; page <= MAX_PAGES; page++) {
    const url = `${BASE}?was=${encodeURIComponent(searches[i])}&${commonParams}&page=${page}`;
    let body;
    try {
      const raw = await this.helpers.httpRequest({ method: 'GET', url, headers: HEADERS });
      body = typeof raw === 'string' ? JSON.parse(raw) : raw;
    } catch (e) { errors.push({ search: searches[i], page, error: e.message || String(e) }); continue; }
    const results = body.stellenangebote || [];
    if (results.length === 0) break;
    for (const s of results) {
      const id = s.refnr || s.titel;
      if (!seenIds.has(id)) { seenIds.add(id); jobs.push(s); }
    }
    const maxPage = body.maxErgebnisse ? Math.ceil(body.maxErgebnisse / 100) : 1;
    if (page >= maxPage) break;
  }
}

if (jobs.length === 0) return [];

// Fetch full descriptions from employer pages (externeUrl)
function decodeEntities(text) {
  return text
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&apos;/g, "'")
    .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)))
    .replace(/&#x([0-9a-fA-F]+);/g, (_, h) => String.fromCharCode(parseInt(h, 16)));
}

const FETCH_DELAY = config.aa_fetch_delay_ms || 300;
const MAX_FETCHES = config.aa_max_fetches || 200;
let fetchCount = 0;
let descFailCount = 0;
for (let i = 0; i < jobs.length && fetchCount < MAX_FETCHES; i++) {
  const extUrl = jobs[i].externeUrl;
  if (!extUrl) continue;
  if (fetchCount > 0) await new Promise(r => setTimeout(r, FETCH_DELAY));
  fetchCount++;
  try {
    const html = await this.helpers.httpRequest({ method: 'GET', url: extUrl, encoding: 'utf-8', timeout: config.aa_fetch_timeout_ms || 5000 });
    let text = String(html).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    text = decodeEntities(text);
    if (text.length > 100) jobs[i]._fullDesc = text.substring(0, config.description_max_chars || 5000);
  } catch (e) { descFailCount++; }
}

const _crawlMeta = {
  source: 'arbeitsagentur',
  searches_run: searches.length,
  total_results: jobs.length,
  fetch_errors: errors.length,
  errors: errors.slice(0, 10),
  descriptions_attempted: fetchCount,
  descriptions_failed: descFailCount,
};

const mapped = jobs.map(j => {
  const company = typeof j.arbeitgeber === 'object' ? (j.arbeitgeber?.name || '') : (j.arbeitgeber || '');
  const location = j.arbeitsort?.ort || '';
  const region = j.arbeitsort?.region || '';
  const extUrl = j.externeUrl || '';
  const refUrl = j.refnr ? `https://www.arbeitsagentur.de/jobsuche/suche?id=${j.refnr}` : '';
  const url = extUrl || refUrl;
  const fallbackDesc = `${j.titel || ''} bei ${company} in ${location}${region ? ' (' + region + ')' : ''}. Beruf: ${j.beruf || ''}. Eintrittsdatum: ${j.eintrittsdatum || 'k.A.'}`;
  const desc = (j._fullDesc || fallbackDesc).substring(0, config.description_max_chars || 5000);
  return { json: {
    source: 'arbeitsagentur',
    external_id: j.refnr || '',
    url: url,
    title: j.titel || '',
    company: company,
    location: location,
    description: desc,
    tags: [],
    remote: false,
    likely_english: false
  }};
});
if (mapped.length > 0) mapped[0].json._crawlMeta = _crawlMeta;
return mapped;

// Deduplicate merged results by normalized company+title
const all = $input.all().filter(i => i.json.url);
const seen = new Set();
const unique = [];

function normalize(s) {
  return (s || '')
    .toLowerCase()
    .trim()
    .replace(/\s+(gmbh|ag|se|kg|co|ltd|inc|ug|mbh|e\.v\.|ohg|gbr)\.?\s*$/i, '')
    .replace(/\s+/g, ' ')
    .replace(/[^\w\s]/g, '');
}

for (const item of all) {
  const job = item.json;
  const key = normalize(job.company) + '|' + normalize(job.title);
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(job);
  }
}

if (unique.length === 0) return [];
return unique.map(j => ({ json: j }));

// Filter out URLs already in Postgres, cap at configurable limit
const config = JSON.parse(require('fs').readFileSync(
  ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/config.json', 'utf-8'
));
const CAP = config.dedup_cap || 80;
let seenRows;
try { seenRows = $('Dedup: Get Seen URLs').all(); } catch (e) { seenRows = []; }
const seenUrls = new Set(seenRows.map(r => r.json.url).filter(Boolean));

const jobs = $('Has Results?').all().filter(item => {
  const url = item.json?.url;
  return url && !seenUrls.has(url);
});

if (jobs.length === 0) return [];
const capped = jobs.slice(0, CAP);
if (jobs.length > CAP && capped.length > 0) {
  capped[0].json._truncated = true;
  capped[0].json._droppedCount = jobs.length - CAP;
}
return capped;

// Build safe INSERT query for each job
// Proper SQL escaping: handles quotes, backslashes, null bytes
function sqlStr(s) {
  if (s === null || s === undefined) return 'NULL';
  return "'" + String(s).replace(/\\/g, '\\\\').replace(/'/g, "''").replace(/\0/g, '') + "'";
}

return $input.all().map(item => {
  const j = item.json;
  const query = `INSERT INTO jobs (url, title, company, location, description, source, external_id, tags, remote, likely_english, salary_min, salary_max, salary_currency) VALUES (${sqlStr(j.url)}, ${sqlStr(j.title)}, ${sqlStr(j.company)}, ${sqlStr(j.location)}, ${sqlStr((j.description || '').substring(0, 10000))}, ${sqlStr(j.source)}, ${sqlStr(j.external_id)}, ${sqlStr(JSON.stringify(j.tags || []))}::jsonb, ${j.remote || false}, ${j.likely_english || false}, ${j.salary_min || 'NULL'}, ${j.salary_max || 'NULL'}, ${sqlStr(j.salary_currency || null)}) ON CONFLICT (url) DO NOTHING`;
  return { json: { _insertQuery: query } };
});

// Check if there are pending jobs
const items = $input.all().filter(i => i.json.id != null);
if (items.length === 0) return [];
return items;

// Batch all pending jobs into groups of N, write each to a temp file
const fs = require('fs');
const config = JSON.parse(fs.readFileSync(
  ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/config.json', 'utf-8'
));
const BATCH_SIZE = config.batch_size || 8;
const all = $input.all();
const tmpDir = ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/temp';

// Ensure temp dir exists and clean old batch files
try { fs.mkdirSync(tmpDir, { recursive: true }); } catch (e) {}
try {
  const oldFiles = fs.readdirSync(tmpDir).filter(f => f.startsWith('n8n_batch_'));
  for (const f of oldFiles) { try { fs.unlinkSync(tmpDir + '/' + f); } catch (e) {} }
} catch (e) {}

const batches = [];
for (let i = 0; i < all.length; i += BATCH_SIZE) {
  const chunk = all.slice(i, i + BATCH_SIZE);
  const batchJobs = chunk.map(item => ({
    title: item.json.title || '',
    company: item.json.company || '',
    location: item.json.location || '',
    description: (item.json.description || '').substring(0, 3000),
    tags: item.json.tags || [],
    url: item.json.url || '',
    _likely_english: item.json.likely_english || false
  }));
  const tmpPath = tmpDir + '/n8n_batch_' + Date.now() + '_' + i + '.json';
  fs.writeFileSync(tmpPath, JSON.stringify(batchJobs), 'utf-8');
  const originals = chunk.map(item => ({
    id: item.json.id,
    url: item.json.url,
    title: item.json.title,
    company: item.json.company,
    location: item.json.location,
    source: item.json.source
  }));
  batches.push({ json: { _tmpPath: tmpPath, _batchOriginals: originals, _batchSize: chunk.length } });
}
return batches;

// Unbatch: match each Claude response to its batch, then build UPDATE SQL
const batchItems = $('Batch Items').all();
const VALID_VARIANTS = ['software', 'data', 'fullstack', 'systems'];
const ERROR_KEYWORDS = ['parse error', 'incomplete', 'timed out', 'filter error', 'claude response parse'];

// Proper SQL escaping: handles quotes, backslashes, null bytes
function sqlStr(s) {
  if (s === null || s === undefined) return 'NULL';
  return "'" + String(s).replace(/\\/g, '\\\\').replace(/'/g, "''").replace(/\0/g, '') + "'";
}

const results = [];
for (let b = 0; b < $input.all().length; b++) {
  const item = $input.all()[b];
  const stdout = item.json.stdout || '[]';
  const originals = (batchItems[b] && batchItems[b].json._batchOriginals) || [];

  let assessments;
  try {
    assessments = JSON.parse(stdout);
    if (!Array.isArray(assessments)) assessments = [assessments];
  } catch (e) {
    for (const orig of originals) {
      results.push({ json: {
        _updateQuery: `UPDATE jobs SET status = 'error', error = ${sqlStr('Failed to parse Claude response: ' + e.message)}, retry_count = retry_count + 1 WHERE id = ${orig.id}`
      }});
    }
    continue;
  }

  for (let i = 0; i < originals.length; i++) {
    const orig = originals[i];
    const assessment = assessments[i];

    if (!assessment) {
      results.push({ json: {
        _updateQuery: `UPDATE jobs SET status = 'error', error = 'No result returned for this job in batch response', retry_count = retry_count + 1 WHERE id = ${orig.id}`
      }});
      continue;
    }

    const rawDecision = String(assessment.decision || 'SKIP').trim().toUpperCase();
    const decision = ['PASS', 'MAYBE', 'SKIP'].includes(rawDecision) ? rawDecision : 'SKIP';
    const score = Number(assessment.fit_score) || 0;

    // Detect batch padding (job was never evaluated by Claude)
    const isBatchPadding = (assessment.priority_notes || '').includes('BATCH_PADDING');

    // Detect fallback/error responses from filter.py
    const isErrorFallback = isBatchPadding || (score === 0 && (assessment.hard_blockers || []).some(b =>
      ERROR_KEYWORDS.some(kw => b.toLowerCase().includes(kw))
    ));

    if (isErrorFallback) {
      results.push({ json: {
        _updateQuery: `UPDATE jobs SET status = 'error', error = ${sqlStr(assessment.reasoning || 'Fallback SKIP from failed Claude call')}, retry_count = retry_count + 1 WHERE id = ${orig.id}`
      }});
      continue;
    }

    // Validate cv_variant
    const cvVariant = VALID_VARIANTS.includes(assessment.cv_variant) ? assessment.cv_variant : 'software';

    results.push({ json: {
      _updateQuery: `UPDATE jobs SET status = 'analyzed', analyzed_at = NOW(), error = NULL, retry_count = 0, fit_score = ${score}, decision = '${decision}', cv_variant = '${cvVariant}', hard_blockers = ${sqlStr(JSON.stringify(assessment.hard_blockers || []))}::jsonb, soft_gaps = ${sqlStr(JSON.stringify(assessment.soft_gaps || []))}::jsonb, strong_matches = ${sqlStr(JSON.stringify(assessment.strong_matches || []))}::jsonb, reasoning = ${sqlStr(assessment.reasoning || '')}, priority_notes = ${sqlStr(assessment.priority_notes || null)} WHERE id = ${orig.id}`
    }});
  }
}
return results;

// Format Postgres rows into Google Sheet columns, skip if no unsynced rows
const all = $input.all().filter(item => item.json.id != null);
if (all.length === 0) return [];

return all.map(item => {
  const j = item.json;
  const crawledAt = j.crawled_at ? new Date(j.crawled_at) : new Date();
  const blockers = Array.isArray(j.hard_blockers) ? j.hard_blockers.join('; ') : (j.hard_blockers || '');
  const matches = Array.isArray(j.strong_matches) ? j.strong_matches.join('; ') : (j.strong_matches || '');
  const decision = j.decision || 'SKIP';

  return { json: {
    'Date': crawledAt.toISOString().slice(0, 10),
    'Fetched At': crawledAt.toISOString().replace('T', ' ').slice(0, 19) + ' UTC',
    'Source': j.source || '',
    'Company': j.company || '',
    'Role': j.title || '',
    'Location': j.location || '',
    'Salary': j.salary_min && j.salary_max
      ? `${j.salary_min}-${j.salary_max} ${j.salary_currency || 'EUR'}`
      : (j.salary_min ? `${j.salary_min}+ ${j.salary_currency || 'EUR'}` : ''),
    'Score': j.fit_score || 0,
    'Decision': decision,
    'CV Variant': j.cv_variant || 'software',
    'Blockers': blockers,
    'Strong Matches': matches,
    'Reasoning': j.reasoning || '',
    'Status': decision === 'SKIP' ? 'skipped' : 'review',
    'Drive Link': '',
    'Job URL': j.url || '',
    'Notes': j.priority_notes || '',
    _dbId: j.id
  }};
});

// Collect all DB IDs that were synced to Sheet and build UPDATE query
let formatItems;
try { formatItems = $('Format Sheet Rows').all(); } catch (e) { formatItems = []; }
const ids = formatItems.map(item => item.json._dbId).filter(Boolean);

if (ids.length === 0) return [{ json: { _syncQuery: 'SELECT 1', _synced: 0 } }];

return [{ json: {
  _syncQuery: `UPDATE jobs SET sheet_synced = TRUE, sheet_synced_at = NOW() WHERE id IN (${ids.join(',')})`,
  _synced: ids.length
}}];

// Collect pipeline run metrics and format for Metrics sheet tab
let formatItems = [];
try { formatItems = $('Format Sheet Rows').all().filter(i => i.json.Date); } catch (e) { /* no items */ }

const pass = formatItems.filter(i => i.json.Decision === 'PASS').length;
const maybe = formatItems.filter(i => i.json.Decision === 'MAYBE').length;
const skip = formatItems.filter(i => i.json.Decision === 'SKIP').length;
const total = pass + maybe + skip;
const now = new Date();

return [{ json: {
  'Date': now.toISOString().slice(0, 10),
  'Timestamp': now.toISOString().replace('T', ' ').slice(0, 19) + ' UTC',
  'Analyzed': total,
  'PASS': pass,
  'MAYBE': maybe,
  'SKIP': skip,
  'Pass Rate': total > 0 ? Math.round(pass / total * 100) + '%' : '0%',
  'Synced': formatItems.length,
}}];
